const body = $input.first().json.body || $input.first().json;
const own_profile_id = body.own_profile_id;
const user_id = body.user_id;
const own_username = (body.own_username || '').toString().replace(/^@/, '').trim().toLowerCase();

if (!own_profile_id) throw new Error('Missing required field: own_profile_id');
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(own_profile_id)) {
  throw new Error('own_profile_id must be a valid UUID');
}
if (!user_id) throw new Error('Missing required field: user_id');
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(user_id)) {
  throw new Error('user_id must be a valid UUID');
}
// own_username is optional but strongly recommended — Parse & Enrich uses
// it to scrub Claude's example_posts of any reference to the user's own
// account that slipped past the prompt rules.

return [{ json: { own_profile_id, user_id, own_username } }];

// Merge own posts and competitor list, validate we have enough, build competitor IDs for next query
// Fetch Own Posts and Fetch Competitors are parallel branches from Validate Input — both will have executed by now.
let ownItems = [];
let compItems = [];
try { ownItems = $('Fetch Own Posts').all(); } catch (e) { ownItems = []; }
try { compItems = $('Fetch Competitors').all(); } catch (e) { compItems = []; }

// HTTP node may return either one item whose json is an array, or N items each a row.
function flatten(items) {
  if (!items || items.length === 0) return [];
  if (items.length === 1 && Array.isArray(items[0].json)) return items[0].json;
  return items.map(i => i.json);
}

const own_posts = flatten(ownItems);
const competitors = flatten(compItems);

const own_profile_id = $('Validate Input').first().json.own_profile_id;

if (own_posts.length === 0) {
  throw new Error(`No posts found for own_profile_id ${own_profile_id}. Scrape your own profile first.`);
}
if (competitors.length < 2) {
  throw new Error(`Need at least 2 competitor profiles. Found: ${competitors.length}. Add and scrape competitors first.`);
}

const competitor_ids = competitors.map(c => c.id);

return [{ json: { own_profile_id, own_posts, competitors, competitor_ids } }];

function sanitize(str) {
  if (!str) return '';
  return str.replace(/[\uD800-\uDFFF]/g, '').replace(/[\x00-\x1F\x7F]/g, ' ').trim();
}

function formatPosts(posts, limit) {
  if (!posts || posts.length === 0) return '  (no posts scraped yet)';
  return posts.slice(0, limit).map((p, i) => {
    const caption = sanitize(p.caption || '').slice(0, 100);
    const date = (p.posted_at || '').slice(0, 10);
    return `  ${String(i+1).padStart(2)}. [${(p.content_type||'unknown').padEnd(8)}] ${date} | L:${p.likes||0} C:${p.comments||0} V:${p.views||0} | "${caption}"`;
  }).join('\n');
}

const upstream = $('Merge Profiles').first().json;
const validate = $('Validate Input').first().json;
const { own_profile_id, own_posts, competitors } = upstream;
const own_username = (validate.own_username || '').toLowerCase();
const ownHandleLabel = own_username ? '@' + own_username : 'own_account';

const allPostsRaw = $input.first().json;
const allPosts = Array.isArray(allPostsRaw) ? allPostsRaw : [allPostsRaw];

const postsByProfile = {};
for (const post of allPosts) {
  if (!postsByProfile[post.profile_id]) postsByProfile[post.profile_id] = [];
  postsByProfile[post.profile_id].push(post);
}

const competitorCount = competitors.length;

const ownSection = '--- USER OWN ACCOUNT (' + ownHandleLabel + ') --- ' + own_posts.length + ' posts, top by likes ---\n' + formatPosts(own_posts, 30);

let competitorSections = '';
for (const comp of competitors) {
  const posts = postsByProfile[comp.id] || [];
  competitorSections += '\n--- COMPETITOR: @' + comp.username + ' (' + posts.length + ' posts) ---\n' + formatPosts(posts, 50) + '\n';
}

const systemPrompt = 'You are a social media growth analyst specialising in Instagram content strategy. Analyze all provided posts and detect content patterns that consistently outperform average engagement. Return ONLY a valid JSON array, no markdown, no code blocks, no explanation outside the JSON. Every recommendation must be concrete enough that the creator can film it tomorrow without asking follow-up questions.';

const userPrompt = 'Analyze the following Instagram posts from ' + competitorCount + ' competitor accounts plus the user own account (' + ownHandleLabel + ').\n\n' +
'The user goal is to discover NEW content ideas inspired by competitors. Even when the user already does a pattern, you must surface what specifically the competitors do BETTER or DIFFERENTLY.\n\n' +
'IDENTIFY CONTENT PATTERNS across all accounts. Consider patterns such as: episodic series, problem/solution, gear review, montage/recap, origin story, vulnerability/personal story, human connection moment, educational how-to, food and culture, scenic adventure, behind-the-scenes, challenge/transformation, Q&A, day-in-life, gear failure/mistake, achievement celebration, myth-busting, comparison, route/destination reveal.\n\n' +
'For EACH pattern identified:\n' +
'1. Determine which competitors have it in their TOP 20% posts by likes\n' +
'2. Default validated trend = appears in top 20% posts of 2+ competitors AND in at least 30% of all tracked competitors\n' +
'3. Calculate performance_multiplier = average likes of posts with this pattern / average likes of all posts for that competitor\n\n' +
ownSection + '\n' + competitorSections + '\n' +
'Return a JSON ARRAY (0-7 items), sorted by performance_multiplier descending. Each item MUST have exactly this structure:\n' +
'{\n' +
'  "trend_name": "Short descriptive name like \'Episodic Series Content\'",\n' +
'  "one_line_summary": "Max 100 characters. Action-oriented.",\n' +
'  "competitor_count": 4,\n' +
'  "total_competitors": ' + competitorCount + ',\n' +
'  "performance_multiplier": 3.2,\n' +
'  "why_it_works": "1-2 sentences explaining the psychological/algorithmic reason this pattern drives engagement",\n' +
'  "competitor_edge": "REQUIRED - one specific concrete thing competitors do differently or better. E.g. \'Competitor X uses 15-second cuts vs your 45-second cuts, getting 3x more engagement.\'",\n' +
'  "example_posts": [\n' +
'    {"caption_preview": "first 80 chars of caption", "likes": 1234, "comments": 56, "competitor": "@username"},\n' +
'    {"caption_preview": "...", "likes": 890, "comments": 34, "competitor": "@differentusername"}\n' +
'  ],\n' +
'  "brief": {\n' +
'    "content": "Describe the format in ONE sentence: length, shot type, pacing.",\n' +
'    "hook": "The literal opening 3 seconds, word-for-word.",\n' +
'    "caption_structure": "Multi-line template using newline characters.",\n' +
'    "best_time": "Specific day + 2-hour window.",\n' +
'    "hashtags": ["bikepacking", "adventurecycling", "biketour"]\n' +
'  },\n' +
'  "user_doing_it": true\n' +
'}\n\n' +
'Critical rules - read these twice before returning:\n\n' +
'Validation thresholds:\n' +
'- competitor_count is the integer number of competitors (NOT the user own account) whose TOP-20% posts show this pattern.\n' +
'- Default rule: competitor_count MUST be >= 2 AND (competitor_count / ' + competitorCount + ') MUST be >= 0.3 (at least 30% of tracked competitors).\n' +
'- FALLBACK: You MUST return AT LEAST 2 trends where user_doing_it is false. If applying the strict rule above produces fewer than 2 such trends, include EMERGING patterns from a single competitor (competitor_count = 1) provided performance_multiplier > 3. The fallback is allowed only to fill the new-ideas quota.\n' +
'- total_competitors is always the integer ' + competitorCount + '.\n\n' +
'example_posts rules:\n' +
'- example_posts must NEVER include posts from the user own account (' + ownHandleLabel + '). Only competitor posts.\n' +
'- example_posts MUST include posts from at least 2 different competitors UNLESS this is an emerging single-competitor fallback trend.\n' +
'- Each example_post.competitor field must be the actual @username of the competitor - never "own_account", never "user", never the user own handle.\n' +
'- A given post (same competitor + same caption) MUST appear in at most ONE trend example_posts. Do not reuse the same post across multiple trends.\n' +
'- Sort example_posts by likes descending.\n\n' +
'competitor_edge rules:\n' +
'- REQUIRED for every trend, including ones where user_doing_it is true.\n' +
'- Must be a concrete observation: a specific stylistic, structural, or production-quality difference. Avoid generic phrases.\n' +
'- For user_doing_it=true trends: contrast what the user does vs what competitors do better.\n' +
'- For user_doing_it=false trends: describe the standout craft choice that makes the pattern land.\n\n' +
'performance_multiplier:\n' +
'- Ratio: (avg likes of posts matching pattern) / (avg likes of ALL posts for that competitor).\n' +
'- Number (not a string) between 1.5 and 25.\n\n' +
'Content rules:\n' +
'- one_line_summary max 100 chars, starts with action verb.\n' +
'- brief.content, brief.hook, brief.caption_structure, brief.best_time are REQUIRED strings. brief.hashtags is a REQUIRED array of 5-8 plain strings without the # prefix.\n' +
'- user_doing_it must be a boolean.\n\n' +
'Return ONLY the JSON array. Empty array [] is acceptable only if NO pattern meets the bar, including the emerging fallback.';

return [{ json: { own_profile_id, own_username, system_prompt: systemPrompt, user_prompt: userPrompt, competitor_count: competitorCount } }];

const resp = $input.first().json;
const rawText = resp?.content?.[0]?.text;
if (!rawText) throw new Error('Claude returned no content. Response: ' + JSON.stringify(resp));

const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let trends;
try {
  trends = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Claude JSON: ' + e.message + '\nRaw: ' + cleaned.slice(0, 500));
}

if (!Array.isArray(trends)) throw new Error('Expected JSON array from Claude, got: ' + typeof trends);

const upstream = $('Build Claude Prompt').first().json;
const own_profile_id = upstream.own_profile_id;
const own_username = (upstream.own_username || '').toLowerCase();
const total_competitors = upstream.competitor_count;

function basics(t) {
  const mult = typeof t.performance_multiplier === 'number' ? t.performance_multiplier : parseFloat(t.performance_multiplier) || 0;
  const compCount = Number.isFinite(t.competitor_count) ? Math.round(t.competitor_count) : 0;
  return { mult, compCount };
}

function meetsStrict(t) {
  const { mult, compCount } = basics(t);
  if (compCount < 2) return false;
  if (total_competitors > 0 && compCount / total_competitors < 0.3) return false;
  if (mult < 1.5 || mult > 25) return false;
  return true;
}

function isEmergingFallback(t) {
  const { mult, compCount } = basics(t);
  if (compCount !== 1) return false;
  if (mult <= 3 || mult > 25) return false;
  if (t.user_doing_it === true) return false;
  return true;
}

const strict = trends.filter(meetsStrict);
const strictNewIdeas = strict.filter(t => t.user_doing_it === false).length;

let admitted = strict.slice();
if (strictNewIdeas < 2) {
  const need = 2 - strictNewIdeas;
  const emerging = trends
    .filter(t => !strict.includes(t) && isEmergingFallback(t))
    .sort((a, b) => (b.performance_multiplier || 0) - (a.performance_multiplier || 0))
    .slice(0, need);
  admitted = strict.concat(emerging);
  console.log('Admitted ' + emerging.length + ' emerging fallback trend(s) to reach the new-ideas floor');
}

const seenExampleKeys = new Set();
function exampleKey(ex) {
  const comp = String(ex.competitor || '').replace(/^@/, '').toLowerCase();
  const cap = String(ex.caption_preview || '').toLowerCase().replace(/\s+/g, ' ').slice(0, 40);
  return comp + '::' + cap;
}

const enriched = admitted.map(t => {
  const examples = Array.isArray(t.example_posts) ? t.example_posts : [];
  const ownScrubbed = examples.filter(ex => {
    const comp = String(ex.competitor || '').replace(/^@/, '').toLowerCase();
    const isOwn =
      comp === 'own_account' ||
      comp === 'user' ||
      (own_username && comp === own_username);
    if (isOwn) console.log('Removed own-handle example from trend "' + t.trend_name + '"');
    return !isOwn;
  });
  const deduped = ownScrubbed.filter(ex => {
    const k = exampleKey(ex);
    if (seenExampleKeys.has(k)) {
      console.log('Removed duplicate example "' + (ex.caption_preview || '').slice(0, 30) + '" from trend "' + t.trend_name + '"');
      return false;
    }
    seenExampleKeys.add(k);
    return true;
  });
  return Object.assign({}, t, { example_posts: deduped });
});

const withExamples = enriched.filter(t => Array.isArray(t.example_posts) && t.example_posts.length > 0);
console.log('After own-scrub + cross-trend dedup: ' + withExamples.length + ' of ' + admitted.length + ' trends retained');

const final = withExamples.map(t => {
  const brief = (t.brief && typeof t.brief === 'object') ? t.brief : {};
  const multiplier = typeof t.performance_multiplier === 'number' ? t.performance_multiplier : parseFloat(t.performance_multiplier) || 0;
  const competitor_count = Number.isFinite(t.competitor_count) ? Math.round(t.competitor_count) : null;
  const effective_total = Number.isFinite(t.total_competitors) ? Math.round(t.total_competitors) : total_competitors;
  const confidence = competitor_count != null && effective_total > 0
    ? competitor_count / effective_total
    : 0;
  const hashtags = Array.isArray(brief.hashtags)
    ? brief.hashtags.map(h => String(h).replace(/^#/, '').trim()).filter(Boolean)
    : null;
  return {
    profile_id: own_profile_id,
    trend_name: t.trend_name || 'Unknown Trend',
    one_line_summary: typeof t.one_line_summary === 'string' ? t.one_line_summary.slice(0, 140) : null,
    competitor_count,
    total_competitors: effective_total,
    confidence,
    performance_multiplier: multiplier,
    why_it_works: t.why_it_works || '',
    competitor_edge: typeof t.competitor_edge === 'string' ? t.competitor_edge.slice(0, 500) : null,
    example_posts: JSON.stringify(t.example_posts || []),
    content_format: typeof brief.content === 'string' ? brief.content : null,
    hook: typeof brief.hook === 'string' ? brief.hook : null,
    caption_structure: typeof brief.caption_structure === 'string' ? brief.caption_structure : null,
    best_time: typeof brief.best_time === 'string' ? brief.best_time : null,
    hashtags: hashtags ? JSON.stringify(hashtags) : null,
    recommendation: t.mega_tip || t.one_line_summary || '',
    suggested_schedule: typeof brief.best_time === 'string' ? brief.best_time : '',
    is_mega_tip: t.user_doing_it === false && multiplier > 2,
    user_doing_it: t.user_doing_it === true
  };
});

console.log('Parsed ' + final.length + ' trends. Mega-tips: ' + final.filter(t => t.is_mega_tip).length);

if (final.length === 0) {
  return [{ json: { _empty: true, profile_id: own_profile_id, total_competitors } }];
}

return final.map(r => ({ json: r }));

// Filter out the _empty sentinel that If-Has-Trends routes around the
// Insert step. Without this, an empty-result run would be reported as
// trends_detected: 1 with a garbage row in the response.
const allUpstream = $('Parse & Enrich Response').all();
const upstream = allUpstream.filter(i => !(i.json && i.json._empty));

const megaTips = upstream.filter(i => i.json.is_mega_tip).length;
const total = upstream.length;

return [{
  json: {
    success: true,
    trends_detected: total,
    mega_tips: megaTips,
    insights: upstream.map(i => ({
      trend_name: i.json.trend_name,
      confidence_label: i.json.confidence_label,
      performance_multiplier: i.json.performance_multiplier,
      is_mega_tip: i.json.is_mega_tip,
      user_doing_it: i.json.user_doing_it
    }))
  }
}];
